    def checksum_value(text: str) -> int:
        return sum(text.encode("utf-8")) % 256

    def parse_checksum(value: str):
        value = value.strip()
        if re.fullmatch(r"[0-9]+", value):
            return int(value)
        if re.fullmatch(r"0x[0-9a-fA-F]+", value):
            return int(value, 16)
        if re.fullmatch(r"[0-9a-fA-F]{2}", value):
