        return bool(re.search(r"\b(invalid|corrupt|bad|error)\b", packet, re.IGNORECASE))

    def validate_json(packet: str) -> bool:
        try:
            obj = json.loads(packet)
        except Exception:
            return False

        if not isinstance(obj, dict):
            return False

        if obj.get("valid") is False:
            return False

        payload = str(obj.get("payload", obj.get("data", "")))

        if "length" in obj:
            try:
                if int(obj["length"]) != len(payload):
                    return False
            except Exception:
                return False

        if "checksum" in obj:
            expected = parse_checksum(str(obj["checksum"]))
            if expected is None or checksum_value(payload) != expected:
                return False

        return True

