                    expected = parse_checksum(keyed.get("checksum", keyed.get("crc", "")))
                    if expected is None or checksum_value(payload) != expected:
                        return False
                return True

            last = parse_checksum(parts[-1])
            if last is not None and len(parts) >= 3:
                body = sep.join(parts[:-1])
                payload = parts[-2]
                if checksum_value(body) == last or checksum_value(payload) == last:
                    return True
                return False

            return all(parts)

        return True

