def solve(packets: list[str]) -> dict[str, float]:
    def is_number(value: Any) -> bool:
        return isinstance(value, (int, float)) and not isinstance(value, bool)

    def to_number(value: Any) -> float | None:
        if is_number(value):
            return float(value)
