        if value is None:
            return []
        if is_number(value):
            return [float(value)]
        if isinstance(value, str):
            nums = []
            for match in re.findall(r'[-+]?(?:\d+(?:\.\d*)?|\.\d+)(?:[eE][-+]?\d+)?', value):
                try:
                    nums.append(float(match))
                except ValueError:
                    pass
