            tokens = []
            for key in ("tokens", "token", "values", "value", "data", "payload", "nums", "numbers", "readings"):
                if key in obj:
                    tokens.extend(extract_numbers(obj[key]))

            if not tokens:
                tokens = extract_numbers(obj)

            channel = str(channel).strip()
            if not channel or not tokens:
                return None
            return channel, tokens

        if isinstance(obj, (list, tuple)) and len(obj) >= 2:
            channel = str(obj[0]).strip()
            tokens = extract_numbers(obj[1:])
            if channel and tokens:
                return channel, tokens

        return None

    def parse_packet(packet: str) -> tuple[str, list[float]] | None:
        if not isinstance(packet, str):
            return None

        text = packet.strip()
        if not text:
            return None

        for loader in (json.loads, ast.literal_eval):
            try:
                parsed = loader(text)
            except Exception:
                continue
            result = parse_structured(parsed)
            if result is not None:
                return result

