                tokens = []
                valid = True
                for part in parts[1:]:
                    number = to_number(part)
                    if number is None:
                        nums = extract_numbers(part)
                        if nums:
                            tokens.extend(nums)
                        else:
                            valid = False
                            break
                    else:
                        tokens.append(number)
                if valid and channel and tokens:
                    return channel, tokens

