import ast
import json
import re
from collections.abc import Iterable

_NUMBER_RE = re.compile(r"[-+]?(?:\d+(?:\.\d*)?|\.\d+)(?:[eE][-+]?\d+)?")
_CHANNEL_KEYS = ("channel", "chan", "ch", "c", "topic", "stream", "name")
_TOKEN_KEYS = ("tokens", "token", "values", "value", "vals", "data", "payload", "items", "readings")


def _is_number(value):
    if isinstance(value, bool):
        return False
    return isinstance(value, (int, float))


def _to_float(value):
    if _is_number(value):
        return float(value)
    if isinstance(value, str):
        s = value.strip()
        if _NUMBER_RE.fullmatch(s):
            return float(s)
    return None


def _numbers_from_text(text):
    return [float(m.group(0)) for m in _NUMBER_RE.finditer(text)]


def _numbers_from_value(value):
    if value is None or isinstance(value, bool):
        return []
    if _is_number(value):
        return [float(value)]
    if isinstance(value, str):
        return _numbers_from_text(value)
    if isinstance(value, dict):
        nums = []
        for k, v in value.items():
            if str(k).lower() not in _CHANNEL_KEYS:
                nums.extend(_numbers_from_value(v))
        return nums
    if isinstance(value, Iterable):
        nums = []
        for item in value:
            nums.extend(_numbers_from_value(item))
        return nums
    return []


def _extract_from_mapping(obj):
    channel = None
    lower_keys = {str(k).lower(): k for k in obj}

    for key in _CHANNEL_KEYS:
        if key in lower_keys:
            channel = str(obj[lower_keys[key]])
            break

    if channel is None:
        for k, v in obj.items():
            if isinstance(v, str) and not _NUMBER_RE.fullmatch(v.strip()):
                channel = v
                break

    if channel is None:
        return None, None

    for key in ("normalized_token_sum", "normalised_token_sum", "normalized_sum", "normalised_sum"):
        if key in lower_keys:
            val = _to_float(obj[lower_keys[key]])
            if val is not None:
                return channel, val

    token_values = []
    for key in _TOKEN_KEYS:
        if key in lower_keys:
            token_values.extend(_numbers_from_value(obj[lower_keys[key]]))

    if not token_values:
        for k, v in obj.items():
            if str(k).lower() not in _CHANNEL_KEYS:
                token_values.extend(_numbers_from_value(v))

    if not token_values:
        return channel, None

    return channel, sum(token_values) / len(token_values)


