        except Exception:
            continue

        if isinstance(obj, dict):
            return _extract_from_mapping(obj)

        if isinstance(obj, (list, tuple)) and obj:
            channel = None
            start = 0
            if isinstance(obj[0], str) and not _NUMBER_RE.fullmatch(obj[0].strip()):
                channel = obj[0]
                start = 1
            nums = _numbers_from_value(obj[start:])
            if channel is not None and nums:
                return str(channel), sum(nums) / len(nums)

