        if isinstance(obj, dict):
            for k, v in obj.items():
                if str(k).lower() == "owner":
                    return clean(v)
            for v in obj.values():
                found = find_owner(v)
                if found:
                    return found
        elif isinstance(obj, list):
            for item in obj:
                found = find_owner(item)
                if found:
                    return found
        return ""

    s = resource.strip()

