        r'(?i)(?<![A-Za-z0-9_])owner(?![A-Za-z0-9_])\s*(?:=|:)\s*(?:"([^"]*)"|\'([^\']*)\'|`([^`]*)`|([^,\s;&}\]\)]+))',
        r'(?i)(?<![A-Za-z0-9_])owner(?![A-Za-z0-9_])\s*\(\s*(?:"([^"]*)"|\'([^\']*)\'|`([^`]*)`|([^)]+))\s*\)',
