def solve(subject: str, resource: str, action: str, policies: list[str]) -> bool:
    allow_seen = False
    deny_seen = False

    allow_words = {"allow", "permit", "accept", "grant", "granted", "yes", "true", "allowed"}
    deny_words = {"deny", "forbid", "reject", "block", "disallow", "prohibit", "false", "no", "denied"}

    def strip_quotes(s):
        s = str(s).strip()
        if len(s) >= 2 and s[0] == s[-1] and s[0] in ("'", '"', "`"):
            return s[1:-1]
        return s

    def split_values(pat):
        pat = strip_quotes(str(pat).strip())
        if pat.startswith("[") and pat.endswith("]"):
            pat = pat[1:-1]
        parts = []
        cur = ""
        quote = None
        for ch in pat:
            if quote:
                cur += ch
                if ch == quote:
                    quote = None
            elif ch in ("'", '"', "`"):
                quote = ch
                cur += ch
            elif ch in ("|", ","):
                if cur.strip():
                    parts.append(strip_quotes(cur.strip()))
                cur = ""
            else:
                cur += ch
        if cur.strip():
            parts.append(strip_quotes(cur.strip()))
        return parts or [pat]

    def one_match(pat, value):
        pat = strip_quotes(str(pat).strip())
        value = str(value)
        if pat in {"*", "any", "ANY", "<any>", "all", "ALL"}:
            return True
        if pat == value:
            return True
        return fnmatch.fnmatchcase(value, pat)

    def pattern_match(pattern, value):
        positives = []
        negatives = []
        for p in split_values(pattern):
            if p.startswith("!") and len(p) > 1:
                negatives.append(p[1:])
            else:
                positives.append(p)
        for p in negatives:
            if one_match(p, value):
                return False
        if not positives:
            return True
        return any(one_match(p, value) for p in positives)

    def effect_of(token):
