_DENY = {"deny", "denied", "forbid", "forbidden", "reject", "rejected", "disallow", "disallowed", "no", "false", "0", "cannot", "can't"}
_FILLER = {"to", "on", "for", "from", "the", "a", "an", "is", "be", "can", "may", "access", "do", "does", "policy", "rule", "p"}
_SUB_KEYS = {"subject", "sub", "user", "principal", "actor", "role", "group", "identity"}
_RES_KEYS = {"resource", "res", "object", "obj", "path", "target", "asset"}
_ACT_KEYS = {"action", "act", "operation", "op", "permission", "perm", "verb"}
_EFF_KEYS = {"effect", "eft", "decision", "access", "result"}


def _clean(v):
    if v is None:
        return ""
    v = str(v).strip()
    if len(v) >= 2 and ((v[0] == v[-1] == '"') or (v[0] == v[-1] == "'")):
        v = v[1:-1]
    return v.strip()


def _effect(v):
    if v is None:
        return None
    s = _clean(v).lower()
    if s in _ALLOW:
        return "allow"
    if s in _DENY:
        return "deny"
    return None


