    pattern = _clean(pattern)
    value = _clean(value)
    if pattern == "":
        return False
    if pattern.lower() in {"*", "any", "all", "<any>", "anyone"}:
        return True
    return (
        value == pattern
        or fnmatch.fnmatchcase(value, pattern)
        or value.lower() == pattern.lower()
        or fnmatch.fnmatchcase(value.lower(), pattern.lower())
    )


