    pattern = _clean(pattern)
    if not pattern:
        return False

    parts = [p.strip() for p in re.split(r"(?<!\\)[,|]", pattern) if p.strip()]
    if not parts:
        parts = [pattern]

    positives = []
    for p in parts:
        neg = False
        lp = p.lower()
        if p.startswith("!"):
            neg = True
            p = p[1:].strip()
        elif lp.startswith("not:"):
            neg = True
