import ast
import fnmatch
import json
import re
import shlex


_ALLOW = {"allow", "allows", "allowed", "permit", "permits", "permitted", "grant", "grants", "granted", "accept", "accepts", "true", "yes", "y", "+"}
_DENY = {"deny", "denies", "denied", "forbid", "forbids", "forbidden", "reject", "rejects", "rejected", "disallow", "disallows", "disallowed", "false", "no", "n", "-"}
_SUBJECT_KEYS = {"subject", "sub", "user", "principal", "actor", "identity", "member"}
_RESOURCE_KEYS = {"resource", "res", "object", "obj", "target", "item", "path"}
_ACTION_KEYS = {"action", "act", "operation", "op", "verb", "permission", "perm"}
_EFFECT_KEYS = {"effect", "eft", "decision", "access", "result", "type"}


def solve(subject: str, resource: str, action: str, policies: list[str]) -> bool:
    best_score = None
    best_effects = []

    for policy in policies or []:
        for effect, subs, ress, acts, score in _applicable_rules(str(policy), subject, resource, action):
            if effect is None:
                continue
            if best_score is None or score > best_score:
                best_score = score
                best_effects = [effect]
            elif score == best_score:
                best_effects.append(effect)

    if best_score is None:
        return False
    if any(e == "deny" for e in best_effects):
        return False
    return any(e == "allow" for e in best_effects)


def _applicable_rules(policy, subject, resource, action):
    policy = policy.strip()
    if not policy or policy.startswith("#") or policy.startswith("//"):
        return []

    out = []

    parsed = _parse_structured(policy)
    if parsed is not None:
        effect, subs, ress, acts = parsed
        score = _rule_score(subs, ress, acts, subject, resource, action)
        if score is not None:
            out.append((effect, subs, ress, acts, score))
        return out

    effect = _find_effect(policy)
    cond_match = re.search(r"\b(?:if|where|when)\b(.+)$", policy, flags=re.I)
    if effect and cond_match:
        expr = cond_match.group(1).strip()
        if _safe_eval(expr, subject, resource, action):
            out.append((effect, None, None, None, 1000))
        return out

    kv = _parse_key_values(policy)
    if kv:
        effect = kv.get("effect") or effect
        subs = kv.get("subject")
        ress = kv.get("resource")
        acts = kv.get("action")
        score = _rule_score(subs, ress, acts, subject, resource, action)
        if score is not None:
            out.append((effect, subs, ress, acts, score))
        return out

    tokens = _tokens(policy)
    if not tokens:
        return out

    effect = effect or _effect_from_tokens(tokens)
    if effect is None:
        return out

    significant = []
    for t in tokens:
        lt = t.lower()
        if lt in _ALLOW or lt in _DENY:
            continue
        if lt in {"p", "policy", "rule", "can", "to", "on", "for", "of", "the", "a", "an", "is", "be", "may"}:
            continue
        if lt in {"cannot", "can't", "cant", "mustnot", "mustn't"}:
            continue
        significant.append(t)

    score = _assign_score(significant, subject, resource, action)
    if score is not None:
        out.append((effect, None, None, None, score))

    return out


def _parse_structured(policy):
    s = policy.strip()
    obj = None

    if (s.startswith("{") and s.endswith("}")) or (s.startswith("[") and s.endswith("]")):
        try:
            obj = json.loads(s)
        except Exception:
            try:
                obj = ast.literal_eval(s)
            except Exception:
                obj = None

    if not isinstance(obj, dict):
        return None

    effect = None
    subs = ress = acts = None

    for k, v in obj.items():
        key = str(k).strip().lower()
        vals = _value_list(v)
        if key in _EFFECT_KEYS:
            effect = _normalize_effect(str(vals[0])) if vals else None
        elif key in _SUBJECT_KEYS:
            subs = vals
        elif key in _RESOURCE_KEYS:
            ress = vals
        elif key in _ACTION_KEYS:
            acts = vals

    return effect, subs, ress, acts


def _parse_key_values(policy):
    res = {}
    pattern = re.compile(r"([A-Za-z_][A-Za-z0-9_-]*)\s*(?:=|:)\s*(\[[^\]]*\]|\([^\)]*\)|\"[^\"]*\"|'[^']*'|[^,;\s]+)")
