import re
import shlex


def solve(subject: str, resource: str, action: str, policies: list[str]) -> bool:
    best_score = None
    best_effects = []

    for policy in policies or []:
        for effect, subs, ress, acts, score in _applicable_rules(str(policy), subject, resource, action):
            if effect is None:
                continue
            if best_score is None or score > best_score:
                best_score = score
                best_effects = [effect]
            elif score == best_score:
                best_effects.append(effect)

    if best_score is None:
        return False
    if any(e == "deny" for e in best_effects):
        return False
    return any(e == "allow" for e in best_effects)


def _applicable_rules(policy, subject, resource, action):
    policy = policy.strip()
    if not policy or policy.startswith("#") or policy.startswith("//"):
        return []

    out = []

    parsed = _parse_structured(policy)
    if parsed is not None:
        effect, subs, ress, acts = parsed
        score = _rule_score(subs, ress, acts, subject, resource, action)
        if score is not None:
            out.append((effect, subs, ress, acts, score))
        return out

    effect = _find_effect(policy)
    cond_match = re.search(r"\b(?:if|where|when)\b(.+)$", policy, flags=re.I)
    if effect and cond_match:
        expr = cond_match.group(1).strip()
        if _safe_eval(expr, subject, resource, action):
            out.append((effect, None, None, None, 1000))
        return out

    kv = _parse_key_values(policy)
    if kv:
        effect = kv.get("effect") or effect
        subs = kv.get("subject")
        ress = kv.get("resource")
        acts = kv.get("action")
        score = _rule_score(subs, ress, acts, subject, resource, action)
        if score is not None:
            out.append((effect, subs, ress, acts, score))
        return out

    tokens = _tokens(policy)
    if not tokens:
        return out

    effect = effect or _effect_from_tokens(tokens)
    if effect is None:
        return out

    significant = []
    for t in tokens:
        lt = t.lower()
        if lt in _ALLOW or lt in _DENY:
            continue
        if lt in {"p", "policy", "rule", "can", "to", "on", "for", "of", "the", "a", "an", "is", "be", "may"}:
            continue
        if lt in {"cannot", "can't", "cant", "mustnot", "mustn't"}:
            continue
        significant.append(t)

    score = _assign_score(significant, subject, resource, action)
    if score is not None:
        out.append((effect, None, None, None, score))

    return out


def _parse_structured(policy):
    s = policy.strip()
    obj = None

    if (s.startswith("{") and s.endswith("}")) or (s.startswith("[") and s.endswith("]")):
        try:
            obj = json.loads(s)
        except Exception:
            try:
                obj = ast.literal_eval(s)
            except Exception:
                obj = None

    if not isinstance(obj, dict):
        return None

    effect = None
    subs = ress = acts = None

    for k, v in obj.items():
        key = str(k).strip().lower()
        vals = _value_list(v)
        if key in _EFFECT_KEYS:
            effect = _normalize_effect(str(vals[0])) if vals else None
        elif key in _SUBJECT_KEYS:
            subs = vals
        elif key in _RESOURCE_KEYS:
            ress = vals
        elif key in _ACTION_KEYS:
            acts = vals

    return effect, subs, ress, acts


def _parse_key_values(policy):
    res = {}
    pattern = re.compile(r"([A-Za-z_][A-Za-z0-9_-]*)\s*(?:=|:)\s*(\[[^\]]*\]|\([^\)]*\)|\"[^\"]*\"|'[^']*'|[^,;\s]+)")
    found = False

    for key, val in pattern.findall(policy):
        k = key.lower()
        if k not in _EFFECT_KEYS and k not in _SUBJECT_KEYS and k not in _RESOURCE_KEYS and k not in _ACTION_KEYS:
            continue
        found = True
        vals = _value_list(val)
        if k in _EFFECT_KEYS:
            res["effect"] = _normalize_effect(str(vals[0])) if vals else None
        elif k in _SUBJECT_KEYS:
            res["subject"] = vals
        elif k in _RESOURCE_KEYS:
            res["resource"] = vals
        elif k in _ACTION_KEYS:
            res["action"] = vals

    return res if found else None


def _find_effect(policy):
    for t in _tokens(policy):
        e = _normalize_effect(t)
        if e:
            return e
    return None


def _effect_from_tokens(tokens):
    low = [t.lower() for t in tokens]
    if any(t in {"cannot", "can't", "cant", "mustnot", "mustn't"} for t in low):
        return "deny"
    for t in low:
        e = _normalize_effect(t)
        if e:
            return e
    if "can" in low or "may" in low:
        return "allow"
    return None


def _normalize_effect(value):
    v = str(value).strip().strip("\"'").lower()
    if v in _ALLOW:
        return "allow"
    if v in _DENY:
        return "deny"
    return None


def _tokens(s):
    s = s.replace("->", " ")
    s = re.sub(r"[,\n\r\t;(){}\[\]]+", " ", s)
    s = re.sub(r"\s+", " ", s).strip()
    if not s:
        return []
    try:
        return [x.strip().strip("\"'") for x in shlex.split(s) if x.strip()]
    except Exception:
        return [x.strip().strip("\"'") for x in s.split() if x.strip()]


def _value_list(v):
    if isinstance(v, (list, tuple, set)):
        return [str(x).strip().strip("\"'") for x in v]
    if v is None:
        return []
    s = str(v).strip()
    try:
        if (s.startswith("[") and s.endswith("]")) or (s.startswith("(") and s.endswith(")")):
            parsed = ast.literal_eval(s)
            if isinstance(parsed, (list, tuple, set)):
                return [str(x).strip().strip("\"'") for x in parsed]
    except Exception:
        pass
    s = s.strip("[]()")
    parts = re.split(r"\s*\|\s*|\s*,\s*", s)
    return [p.strip().strip("\"'") for p in parts if p.strip()]


def _rule_score(subs, ress, acts, subject, resource, action):
    if subs is None and ress is None and acts is None:
        return None
    s1 = _best_match_score(subs if subs is not None else ["*"], subject)
    s2 = _best_match_score(ress if ress is not None else ["*"], resource)
    s3 = _best_match_score(acts if acts is not None else ["*"], action)
    if s1 is None or s2 is None or s3 is None:
        return None
    return s1 + s2 + s3 + 100


def _assign_score(tokens, subject, resource, action):
    if len(tokens) < 3:
        return None

    vals = [subject, resource, action]
    used = [False] * len(tokens)
    best = None

    def backtrack(i, score):
        nonlocal best
        if i == 3:
            best = score if best is None else max(best, score)
            return
        for idx, tok in enumerate(tokens):
            if used[idx]:
                continue
            m = _match_score(tok, vals[i])
            if m is not None:
                used[idx] = True
                backtrack(i + 1, score + m)
                used[idx] = False

    backtrack(0, 0)
    return best


def _best_match_score(patterns, value):
    best = None
    for p in _value_list(patterns):
        sc = _match_score(p, value)
        if sc is not None:
            best = sc if best is None else max(best, sc)
    return best


def _match_score(pattern, value):
    p = str(pattern).strip().strip("\"'")
    v = str(value)

    if p in {"*", "any", "ANY", "all", "ALL"}:
        return 0

    if p == v:
        return 10

    if p.lower() == v.lower():
        return 9

    if any(ch in p for ch in "*?[]"):
        if fnmatch.fnmatchcase(v, p):
            return 4
        if fnmatch.fnmatch(v.lower(), p.lower()):
            return 3

    if p.endswith(":*") and v.lower().startswith(p[:-1].lower()):
        return 2

    return None


def _safe_eval(expr, subject, resource, action):
    try:
        tree = ast.parse(expr, mode="eval")
    except Exception:
        return False

    names = {
        "subject": subject,
        "sub": subject,
        "user": subject,
        "principal": subject,
        "resource": resource,
        "res": resource,
        "object": resource,
        "obj": resource,
        "action": action,
        "act": action,
        "operation": action,
        "op": action,
        "True": True,
        "False": False,
    }

    def ev(node):
        if isinstance(node, ast.Expression):
            return ev(node.body)
        if isinstance(node, ast.BoolOp):
            vals = [bool(ev(v)) for v in node.values]
            return all(vals) if isinstance(node.op, ast.And) else any(vals)
        if isinstance(node, ast.UnaryOp) and isinstance(node.op, ast.Not):
            return not bool(ev(node.operand))
        if isinstance(node, ast.Compare):
            left = ev(node.left)
            for op, comp in zip(node.ops, node.comparators):
                right = ev(comp)
                if isinstance(op, ast.Eq):
                    ok = left == right
                elif isinstance(op, ast.NotEq):
                    ok = left != right
                elif isinstance(op, ast.In):
                    ok = left in right
                elif isinstance(op, ast.NotIn):
                    ok = left not in right
                else:
                    return False
                if not ok:
                    return False
                left = right
            return True
        if isinstance(node, ast.Name):
            if node.id in names:
                return names[node.id]
            raise ValueError
        if isinstance(node, ast.Constant):
            return node.value
        if isinstance(node, (ast.List, ast.Tuple, ast.Set)):
            return [ev(x) for x in node.elts]
        raise ValueError

    try:
        return bool(ev(tree))
    except Exception:
        return False

