import re
import ast
import fnmatch
import shlex


def solve(subject: str, resource: str, action: str, policies: list[str]) -> bool:
    env = {"subject": subject, "resource": resource, "action": action}

    allow_words = {"allow", "allowed", "permit", "permitted", "grant", "granted", "accept", "approve"}
    deny_words = {"deny", "denied", "forbid", "forbidden", "reject", "revoke", "disallow", "block"}
    filler_words = {
        "policy", "rule", "can", "cannot", "cant", "may", "to", "on", "for", "of", "the", "a", "an",
        "is", "be", "do", "does", "if", "when", "then", "with", "where", "and", "or"
    }

    subj_keys = {"subject", "sub", "user", "principal", "actor", "identity", "who"}
    res_keys = {"resource", "res", "object", "obj", "target", "asset", "item", "what"}
    act_keys = {"action", "act", "operation", "op", "verb", "permission"}
    effect_keys = {"effect", "decision", "result"}

    def strip_quotes(v):
        v = str(v).strip()
        if len(v) >= 2 and ((v[0] == v[-1] == "'") or (v[0] == v[-1] == '"')):
            return v[1:-1]
        return v

    def is_wildcard(v):
        return str(v).strip().lower() in {"*", "any", "all", "anyone", "anything", "everything", "_"}

    def value_match(pattern, value):
        if pattern is None:
            return True
        if isinstance(pattern, (list, tuple, set)):
            return any(value_match(p, value) for p in pattern)

        p = strip_quotes(pattern)
        if is_wildcard(p):
            return True

        neg = False
        if p.startswith("!"):
            neg = True
            p = p[1:]

        parts = []
        for sep in ("|", "/"):
            if sep in p and not p.startswith("/"):
                parts = [x for x in p.split(sep) if x != ""]
                break
        if parts:
            ok = any(value_match(x, value) for x in parts)
            return not ok if neg else ok

        ok = fnmatch.fnmatchcase(value, p)
        if not ok:
            ok = value == p
        return not ok if neg else ok

    class SafeEval(ast.NodeVisitor):
        def visit_Expression(self, node):
            return self.visit(node.body)

        def visit_BoolOp(self, node):
            if isinstance(node.op, ast.And):
                return all(self.visit(v) for v in node.values)
            if isinstance(node.op, ast.Or):
                return any(self.visit(v) for v in node.values)
            raise ValueError

        def visit_UnaryOp(self, node):
            if isinstance(node.op, ast.Not):
                return not self.visit(node.operand)
            raise ValueError

        def visit_Compare(self, node):
            left = self.visit(node.left)
            for op, comp in zip(node.ops, node.comparators):
                right = self.visit(comp)
                if isinstance(op, ast.Eq):
                    ok = left == right or value_match(right, left)
                elif isinstance(op, ast.NotEq):
                    ok = not (left == right or value_match(right, left))
                elif isinstance(op, ast.In):
                    ok = left in right if not isinstance(right, str) else value_match(right, left)
                elif isinstance(op, ast.NotIn):
                    ok = not (left in right if not isinstance(right, str) else value_match(right, left))
                else:
                    raise ValueError
                if not ok:
                    return False
                left = right
            return True

        def visit_Name(self, node):
            lid = node.id.lower()
            if node.id in env:
                return env[node.id]
            if lid == "true":
                return True
            if lid == "false":
                return False
            if lid == "none":
                return None
            return node.id

        def visit_Constant(self, node):
            return node.value

        def visit_Str(self, node):
            return node.s

        def visit_List(self, node):
            return [self.visit(e) for e in node.elts]

        def visit_Tuple(self, node):
            return tuple(self.visit(e) for e in node.elts)

        def visit_Set(self, node):
            return {self.visit(e) for e in node.elts}

