            raise ValueError

    def normalize_expr(expr):
        expr = expr.strip()
        expr = expr.replace("&&", " and ").replace("||", " or ")
        expr = re.sub(r"(?<![=!<>])!(?!=)", " not ", expr)
        expr = re.sub(r"\bAND\b", "and", expr)
        expr = re.sub(r"\bOR\b", "or", expr)
        expr = re.sub(r"\bNOT\b", "not", expr)
        return expr

