        found = []
        for m in re.finditer(r"\b([A-Za-z_][A-Za-z0-9_-]*)\b", text):
            w = m.group(1).lower()
            if w in allow_words:
                found.append(("allow", m.start()))
            elif w in deny_words or w in {"cannot", "cant"}:
                found.append(("deny", m.start()))
        if not found:
            return None
        return min(found, key=lambda x: x[1])[0]

    def split_rules(policy):
        if policy is None:
            return []
        s = str(policy)
        lines = []
        for line in s.splitlines():
            line = re.sub(r"#.*$", "", line)
            line = re.sub(r"//.*$", "", line)
            for part in re.split(r";+", line):
                part = part.strip()
                if part:
                    lines.append(part)
        return lines

    def parse_keyed(text):
        constraints = {}
        effect = None

        pattern = re.compile(
            r"\b([A-Za-z_][A-Za-z0-9_-]*)\s*(?:==|=|:|is\s+|in\s+)\s*"
            r"(\[[^\]]*\]|\"[^\"]*\"|'[^']*'|[^\s,;)]+)",
            re.IGNORECASE,
        )
        for k, v in pattern.findall(text):
            kl = k.lower()
            v = strip_quotes(v.strip())
            if v.startswith("[") and v.endswith("]"):
                inside = v[1:-1].strip()
                vals = []
                if inside:
                    try:
                        vals = [strip_quotes(x) for x in ast.literal_eval(v)]
                    except Exception:
                        vals = [strip_quotes(x.strip()) for x in inside.split(",")]
                v = vals
            if kl in subj_keys:
                constraints["subject"] = v
            elif kl in res_keys:
                constraints["resource"] = v
            elif kl in act_keys:
                constraints["action"] = v
            elif kl in effect_keys:
                vl = str(v).lower()
                if vl in allow_words:
                    effect = "allow"
                elif vl in deny_words:
                    effect = "deny"

        return constraints, effect

    def matches_constraints(constraints):
        if "subject" in constraints and not value_match(constraints["subject"], subject):
            return False
        if "resource" in constraints and not value_match(constraints["resource"], resource):
            return False
        if "action" in constraints and not value_match(constraints["action"], action):
            return False
        return True

    def positional_match(text):
        cleaned = re.sub(r"['\"]", "", text)
        cleaned = re.sub(r"[,;(){}\[\]]", " ", cleaned)
        cleaned = cleaned.replace(":", " ").replace("->", " ").replace("=>", " ")
        toks = [t for t in re.split(r"\s+", cleaned.strip()) if t]

        kept = []
        for t in toks:
            tl = t.lower()
            if tl in allow_words or tl in deny_words or tl in filler_words:
                continue
            if tl in subj_keys or tl in res_keys or tl in act_keys or tl in effect_keys:
                continue
            if re.fullmatch(r"\d+", t):
                continue
            if any(op in t for op in ("=", "==")):
                continue
            kept.append(t)

        if len(kept) < 3:
            return False

        triples = []
        for i in range(len(kept) - 2):
            triples.append((kept[i], kept[i + 1], kept[i + 2]))

        for a, b, c in triples:
            if value_match(a, subject) and value_match(b, resource) and value_match(c, action):
                return True
            if value_match(a, subject) and value_match(b, action) and value_match(c, resource):
                return True
        return False

    decisions = []

    for policy in policies or []:
        for rule in split_rules(policy):
            effect = extract_effect(rule)

            constraints, keyed_effect = parse_keyed(rule)
            if effect is None:
                effect = keyed_effect
            if effect not in {"allow", "deny"}:
                continue

            expr_ok = True
            m = re.search(r"\b(?:if|when|where)\b(.+)$", rule, re.IGNORECASE)
            if m:
                expr = m.group(1).strip()
                expr = re.sub(r"^\s*then\b", "", expr, flags=re.IGNORECASE).strip()
                if any(x in expr for x in ("subject", "resource", "action", "&&", "||", "==", "!=", " in ")):
                    r = eval_expr(expr)
                    if r is not None:
                        expr_ok = r

            if not expr_ok:
                continue

            if constraints:
                if matches_constraints(constraints):
                    decisions.append(effect)
            else:
                expr_only = False
                m2 = re.search(r"\b(?:if|when|where)\b(.+)$", rule, re.IGNORECASE)
                if m2:
                    r = eval_expr(m2.group(1))
                    if r is True:
                        expr_only = True
                if expr_only or positional_match(rule):
                    decisions.append(effect)

    if "deny" in decisions:
        return False
    return "allow" in decisions

