    import re
    import fnmatch
    from collections import defaultdict

    def clean_token(s):
        s = str(s).strip()
        while s and s[0] in "([{":
            s = s[1:].strip()
        while s and s[-1] in ")]}":
            s = s[:-1].strip()
        if (len(s) >= 2) and ((s[0] == s[-1] == '"') or (s[0] == s[-1] == "'")):
            s = s[1:-1]
        return s.strip()

    def tokenize(line):
        return [clean_token(x) for x in re.findall(r'"[^"]*"|\'[^\']*\'|\[[^\]]*\]|[^,\s;|]+', line) if clean_token(x)]

    def split_values(value):
        value = clean_token(value)
        if not value:
            return []
        parts = []
        for p in re.split(r"[,\s]+", value):
            p = clean_token(p)
            if p:
                parts.append(p)
        return parts

    def is_wildcard(x):
        return x in {"*", "any", "all", "<any>"}

    def strip_kind(x):
        lx = x.lower()
        for prefix in ("user:", "subject:", "sub:", "principal:", "role:", "group:"):
            if lx.startswith(prefix):
