        for k, v in re.findall(r"([A-Za-z_][A-Za-z0-9_-]*)\s*[:=]\s*(\[[^\]]*\]|\"[^\"]*\"|'[^']*'|[^\s;]+)", line):
            pairs[k.lower()] = clean_token(v)

