        res = None
        acts = None
        eff = None

        for k in ("subject", "sub", "user", "principal", "actor"):
            if k in pairs:
                subj = pairs[k]
                break
        for k in ("resource", "res", "object", "obj", "target"):
            if k in pairs:
                res = pairs[k]
                break
        for k in ("action", "actions", "act", "permission", "permissions"):
            if k in pairs:
                acts = split_values(pairs[k])
                break
        for k in ("effect", "eft", "decision", "access"):
