import json
import re
import shlex


def solve(subject: str, resource: str, action: str, policies: list[str]) -> bool:
    def clean(value):
        if value is None:
            return ""
        value = str(value).strip()
        if len(value) >= 2 and value[0] == value[-1] and value[0] in ("'", '"'):
            value = value[1:-1]
        return value.strip()

    def component_matches(pattern, value):
        pattern = clean(pattern)
        value = clean(value)

        if pattern in ("*", "any", "ANY", "all", "ALL"):
            return True

        if "|" in pattern:
            return any(component_matches(part, value) for part in pattern.split("|"))

        if pattern.startswith("{") and pattern.endswith("}"):
            return any(component_matches(part, value) for part in pattern[1:-1].split(","))

        if any(ch in pattern for ch in "*?["):
            return fnmatch.fnmatchcase(value, pattern)

        return pattern == value

    def triple_matches(sub_pat, res_pat, act_pat):
        return (
            component_matches(sub_pat, subject)
            and component_matches(res_pat, resource)
            and component_matches(act_pat, action)
        )

    effect_words = {
        "allow", "allowed", "permit", "permitted", "accept", "grant", "granted",
        "deny", "denied", "forbid", "forbidden", "reject", "rejected",
    }

    subject_keys = {"subject", "sub", "user", "principal", "identity", "role"}
    resource_keys = {"resource", "res", "obj", "object", "target"}
    action_keys = {"action", "act", "operation", "op", "verb", "permission"}
    policy_markers = {"p", "policy", "rule"}

    def check_dict(d):
        lowered = {str(k).lower(): v for k, v in d.items()}

        sub = next((lowered[k] for k in subject_keys if k in lowered), None)
        res = next((lowered[k] for k in resource_keys if k in lowered), None)
        act = next((lowered[k] for k in action_keys if k in lowered), None)

        return sub is not None and res is not None and act is not None and triple_matches(sub, res, act)

    def check_sequence(seq):
        tokens = [clean(x) for x in seq if clean(x) != ""]
        if not tokens:
            return False

        if tokens and tokens[0].lower() in policy_markers:
            tokens = tokens[1:]

        if tokens and tokens[0].lower() in effect_words:
            rest = tokens[1:]
            if len(rest) >= 3:
                if triple_matches(rest[0], rest[1], rest[2]):
                    return True
                if triple_matches(rest[0], rest[2], rest[1]):
                    return True

