            rest = tokens[:-1]
            if len(rest) >= 3 and triple_matches(rest[0], rest[1], rest[2]):
                return True

        filtered = [
            t for t in tokens
            if t.lower() not in effect_words and t.lower() not in policy_markers and t not in {"=", "=>", ":"}
        ]

        return len(filtered) >= 3 and triple_matches(filtered[0], filtered[1], filtered[2])

    for policy in policies:
        if policy is None:
            continue

        raw = str(policy).strip()
        if not raw or raw.startswith("#"):
            continue

        try:
            parsed = json.loads(raw)
            if isinstance(parsed, dict) and check_dict(parsed):
