            not any(len(ts) >= 3 for ts in token_sets)
            and " " not in raw
            and "," not in raw
            and ";" not in raw
            and raw.count(":") in (3, 4)
        ):
            token_sets.append(raw.split(":"))

        for tokens in token_sets:
