import json
import csv
import shlex
import fnmatch
from typing import Any


_ALLOW = {"allow", "allowed", "permit", "permitted", "yes", "true", "grant", "granted", "can", "may"}
_DENY = {"deny", "denied", "forbid", "forbidden", "no", "false", "disallow", "disallowed", "cannot", "can't"}
_EFFECTS = _ALLOW | _DENY

_SUBJECT_KEYS = {"sub", "subject", "subjects", "principal", "principals", "user", "users", "identity", "identities", "role", "roles"}
_RESOURCE_KEYS = {"res", "resource", "resources", "obj", "object", "objects", "target", "targets"}
_ACTION_KEYS = {"act", "action", "actions", "operation", "operations", "verb", "verbs", "permission", "permissions"}
_EFFECT_KEYS = {"eft", "effect", "decision", "access", "result"}


def _flatten(value: Any) -> list[str]:
    if value is None:
        return []
    if isinstance(value, str):
        return [value]
    if isinstance(value, (int, float, bool)):
        return [str(value)]
    if isinstance(value, dict):
        out = []
        for v in value.values():
            out.extend(_flatten(v))
        return out
    if isinstance(value, (list, tuple, set)):
        out = []
        for v in value:
            out.extend(_flatten(v))
        return out
    return [str(value)]


def _split_patterns(values: Any) -> list[str]:
    out = []
    for value in _flatten(values):
        for part in str(value).replace(";", "|").split("|"):
            part = part.strip().strip("\"'")
            if part:
                out.append(part)
    return out


def _is_any(pattern: str) -> bool:
    return pattern.strip().lower() in {"*", "any", "all", ".*"}


def _match_one(value: str, pattern: str, case_insensitive: bool = False) -> bool:
    pattern = str(pattern).strip().strip("\"'")
    value = str(value)
    if _is_any(pattern):
        return True
    if case_insensitive:
        return fnmatch.fnmatchcase(value.lower(), pattern.lower())
    return fnmatch.fnmatchcase(value, pattern)


def _match_any(value: str, patterns: Any, case_insensitive: bool = False) -> bool:
    pats = _split_patterns(patterns)
    if not pats:
        return True
    return any(_match_one(value, p, case_insensitive) for p in pats)


def _effect_value(value: Any) -> str:
    vals = _flatten(value)
    if not vals:
        return "allow"
    v = str(vals[0]).strip().lower()
    return "deny" if v in _DENY else "allow"


def _ci_get(d: dict, *names: str) -> Any:
    wanted = {n.lower() for n in names}
    for k, v in d.items():
        if str(k).lower() in wanted:
            return v
    return None


def _json_rules(obj: Any) -> list[dict]:
    rules = []

    if isinstance(obj, list):
        for item in obj:
            rules.extend(_json_rules(item))
        return rules

    if not isinstance(obj, dict):
        return rules

    statements = _ci_get(obj, "statement", "statements")
    if statements is not None:
        rules.extend(_json_rules(statements))
        return rules

    effect = _effect_value(_ci_get(obj, "effect", "eft", "decision", "access", "result"))

    principal = _ci_get(obj, "principal", "principals", "subject", "subjects", "user", "users")
    not_principal = _ci_get(obj, "notprincipal", "not_principals", "notsubject", "not_subject")
    subjects = principal if principal is not None else not_principal

    action = _ci_get(obj, "action", "actions", "act", "operation", "operations", "permission", "permissions")
    not_action = _ci_get(obj, "notaction", "not_actions", "notact")
    actions = action if action is not None else not_action

    resource = _ci_get(obj, "resource", "resources", "res", "object", "objects", "obj", "target", "targets")
    not_resource = _ci_get(obj, "notresource", "not_resources", "notres")
    resources = resource if resource is not None else not_resource

    rules.append({
        "effect": effect,
        "subjects": _split_patterns(subjects) if subjects is not None else [],
        "actions": _split_patterns(actions) if actions is not None else [],
        "resources": _split_patterns(resources) if resources is not None else [],
        "not_subject": not_principal is not None and principal is None,
        "not_action": not_action is not None and action is None,
        "not_resource": not_resource is not None and resource is None,
    })
    return rules


def _tokenize_policy(text: str) -> list[str]:
    text = text.strip()
    if not text:
        return []
    if "," in text:
        try:
            return [x.strip() for x in next(csv.reader([text], skipinitialspace=True)) if x.strip()]
        except Exception:
            pass
    try:
        return [x.strip() for x in shlex.split(text) if x.strip()]
    except Exception:
        return [x.strip() for x in text.replace(",", " ").split() if x.strip()]


def _text_rule(text: str, requested_subject: str, requested_action: str) -> dict | None:
    stripped = text.strip()
    if not stripped:
        return None

    for marker in ("#", "//"):
        pos = stripped.find(marker)
        if pos == 0:
            return None
        if pos > 0:
            stripped = stripped[:pos].strip()

    tokens = _tokenize_policy(stripped)
    if not tokens:
        return None

    if tokens[0].lower() in {"p", "policy", "acl", "rule"}:
        tokens = tokens[1:]

    kv = {}
    used = set()
    key_sets = _SUBJECT_KEYS | _RESOURCE_KEYS | _ACTION_KEYS | _EFFECT_KEYS

    i = 0
    while i < len(tokens):
        tok = tokens[i].strip()
        low = tok.lower().strip()
        key = val = None

        if "=" in tok:
            key, val = tok.split("=", 1)
        elif ":" in tok and not tok.lower().startswith(("http:", "https:", "arn:")):
            key, val = tok.split(":", 1)
            if val == "" and i + 1 < len(tokens):
                val = tokens[i + 1]
                used.add(i + 1)
        elif low.rstrip(":=") in key_sets and i + 1 < len(tokens):
            key = low.rstrip(":=")
            val = tokens[i + 1]
            used.add(i + 1)

        if key is not None:
            key = key.strip().lower().replace("-", "_")
            val = str(val).strip().strip("\"'")
            if key in _SUBJECT_KEYS:
                kv.setdefault("subjects", []).extend(_split_patterns(val))
            elif key in _RESOURCE_KEYS:
                kv.setdefault("resources", []).extend(_split_patterns(val))
            elif key in _ACTION_KEYS:
                kv.setdefault("actions", []).extend(_split_patterns(val))
            elif key in _EFFECT_KEYS:
                kv["effect"] = _effect_value(val)
            used.add(i)
        i += 1

    if kv:
        return {
            "effect": kv.get("effect", "allow"),
            "subjects": kv.get("subjects", []),
            "actions": kv.get("actions", []),
            "resources": kv.get("resources", []),
            "not_subject": False,
            "not_action": False,
            "not_resource": False,
        }

    effect = None
    effect_index = None
    for idx, tok in enumerate(tokens):
        low = tok.lower()
        if low in _EFFECTS:
            effect = "deny" if low in _DENY else "allow"
            effect_index = idx
            break

    if effect_index is not None:
        tokens = tokens[:effect_index] + tokens[effect_index + 1:]
    else:
        effect = "allow"

    tokens = [t.strip().strip("\"'") for t in tokens if t.strip()]
    if not tokens:
        return None

    subjects = []
    actions = []
    resources = []

    subject_idx = None
    for idx, tok in enumerate(tokens):
        if _match_one(requested_subject, tok):
            subject_idx = idx
            break
    if subject_idx is None and len(tokens) >= 3:
        subject_idx = 0

    action_idx = None
    for idx, tok in enumerate(tokens):
        if idx != subject_idx and _match_one(requested_action, tok, True):
            action_idx = idx
            break

    if len(tokens) == 1:
        resources = [tokens[0]]
    elif len(tokens) == 2:
        if action_idx is not None:
            actions = [tokens[action_idx]]
            resources = [tokens[1 - action_idx]]
        else:
            subjects = [tokens[0]]
            resources = [tokens[1]]
    else:
        if subject_idx is not None:
            subjects = [tokens[subject_idx]]
        if action_idx is not None:
            actions = [tokens[action_idx]]

        remaining = [tok for idx, tok in enumerate(tokens) if idx not in {subject_idx, action_idx}]
        if remaining:
            resources = remaining
        elif len(tokens) >= 3:
            subjects = [tokens[0]]
            resources = [tokens[1]]
            actions = [tokens[2]]

        if not actions and len(tokens) >= 3:
            subjects = [tokens[0]]
            resources = [tokens[1]]
            actions = [tokens[2]]

    return {
        "effect": effect,
        "subjects": _split_patterns(subjects),
        "actions": _split_patterns(actions),
        "resources": _split_patterns(resources),
        "not_subject": False,
        "not_action": False,
        "not_resource": False,
    }


def _parse_policy(policy: str, subject: str, action: str) -> list[dict]:
    if policy is None:
        return []
    text = str(policy).strip()
    if not text:
        return []

    try:
        return _json_rules(json.loads(text))
    except Exception:
        pass

    rule = _text_rule(text, subject, action)
    return [rule] if rule is not None else []


def _rule_matches(rule: dict, subject: str, action: str, resource: str) -> bool:
    subject_match = _match_any(subject, rule.get("subjects", []))
    if rule.get("not_subject"):
        subject_match = not subject_match
    if not subject_match:
        return False

    action_match = _match_any(action, rule.get("actions", []), True)
    if rule.get("not_action"):
        action_match = not action_match
    if not action_match:
        return False

    resource_match = _match_any(resource, rule.get("resources", []))
    if rule.get("not_resource"):
        resource_match = not resource_match
    return resource_match


def solve(subject: str, resources: list[str], action: str, policies: list[str]) -> list[str]:
    rules = []
    for policy in policies:
        rules.extend(_parse_policy(policy, subject, action))

    allowed_resources = []
    for resource in resources:
        allowed = False
        denied = False

        for rule in rules:
            if _rule_matches(rule, subject, action, resource):
                if rule.get("effect", "allow") == "deny":
                    denied = True
                else:
                    allowed = True

        if allowed and not denied:
            allowed_resources.append(resource)

    return allowed_resources

