    if not action_match:
        return False

    resource_match = _match_any(resource, rule.get("resources", []))
    if rule.get("not_resource"):
        resource_match = not resource_match
    return resource_match


def solve(subject: str, resources: list[str], action: str, policies: list[str]) -> list[str]:
    rules = []
    for policy in policies:
        rules.extend(_parse_policy(policy, subject, action))

    allowed_resources = []
    for resource in resources:
