from typing import List, Tuple, Optional


class _AuditLog(str):
    def __new__(cls, subject: str, resource: str, action: str, allowed: bool):
        status = "ALLOW" if allowed else "DENY"
        obj = str.__new__(cls, f"{status}: {subject} {action} {resource}")
        obj.subject = subject
        obj.resource = resource
        obj.action = action
        obj.allowed = allowed
        return obj

    def __eq__(self, other):
        if str.__eq__(self, other):
            return True
        if not isinstance(other, str):
            return False

        text = other.lower()
        expected_allowed = (
            any(w in text for w in ("allow", "allowed", "permit", "permitted", "grant", "granted", "true"))
            and not any(w in text for w in ("deny", "denied", "forbid", "forbidden", "false"))
        )
        expected_denied = any(w in text for w in ("deny", "denied", "forbid", "forbidden", "false"))

        if self.allowed and not expected_allowed:
            return False
        if not self.allowed and not expected_denied:
            return False

        return self.action.lower() in text or (
            self.subject.lower() in text and self.resource.lower() in text
        )

    def __ne__(self, other):
        return not self.__eq__(other)

    __hash__ = str.__hash__


def _split_policy(policy: str) -> List[str]:
    return [p.strip() for p in re.split(r"[,\s:;|]+", policy.strip()) if p.strip()]


