    parts = _split_policy(policy)
    if not parts:
        return None

    if parts and parts[0].lower() in {"p", "policy"}:
        parts = parts[1:]

    effects = {
        "allow": "allow",
        "allowed": "allow",
        "permit": "allow",
        "permitted": "allow",
        "grant": "allow",
        "granted": "allow",
        "deny": "deny",
        "denied": "deny",
        "forbid": "deny",
        "forbidden": "deny",
    }

    effect_idx = None
    effect = None
    for i, part in enumerate(parts):
        low = part.lower()
        if low in effects:
            effect_idx = i
            effect = effects[low]
            break

    if effect_idx is None:
        if len(parts) >= 3:
            return parts[0], parts[1], parts[2], "allow"
        return None

    remaining = parts[:effect_idx] + parts[effect_idx + 1:]

    if len(remaining) >= 3:
        if effect_idx == 0:
            return remaining[0], remaining[1], remaining[2], effect
        return remaining[0], remaining[1], remaining[2], effect

    return None


