from typing import Any


def solve(subjects: list[str], resource: str, policies: list[str]) -> str | None:
    allow_words = {"allow", "allowed", "permit", "permitted", "grant", "granted", "can"}
    deny_words = {
        "deny", "denied", "disallow", "disallowed", "forbid", "forbidden",
        "cannot", "can't", "cant", "not"
    }
    stop_words = {
        "p", "policy", "can", "may", "to", "on", "in", "at", "for", "of", "the",
        "a", "an", "is", "be", "by", "with", "and", "or", "as", "has", "have",
        "subject", "sub", "user", "principal", "resource", "res", "object",
        "obj", "action", "act", "operation", "effect"
    }

    allowed: dict[str, set[str]] = {s: set() for s in subjects}
    denied: dict[str, set[str]] = {s: set() for s in subjects}

    subject_set = set(subjects)

    def as_list(value: Any) -> list[Any]:
        if value is None:
            return []
        if isinstance(value, (list, tuple, set)):
            return list(value)
        return [value]

    def wildcard_resource(value: str) -> bool:
        return value in {"*", "all", "any"}

    def wildcard_subject(value: str) -> bool:
        return value in {"*", "all", "any", "everyone", "anyone"}

    def effect_of(value: Any) -> str:
        if value is None:
            return "allow"
        text = str(value).strip().lower()
        if text in deny_words or text in {"false", "0", "reject", "rejected"}:
            return "deny"
        return "allow"

    def clean_token(token: str) -> str:
        return token.strip().strip("\"'`[](){}<>")

