            if not text:
                continue
            parts = re.split(r"\s*(?:,|;|\||\+|&|/)\s*|\s+", text)
            for part in parts:
                part = clean_token(part)
                if part:
                    result.append(part)
        return result

    def key_lookup(d: dict, names: set[str]) -> Any:
        for k, v in d.items():
            if str(k).lower() in names:
                return v
        return None

    def apply_entry(sub_values: list[Any], res_values: list[Any], actions: list[str], effect: str) -> None:
