        if not matched_subjects:
            return

        target = denied if effect == "deny" else allowed
        for sub in matched_subjects:
            target[sub].update(actions)

    def parse_json_policy(policy: str) -> bool:
        try:
            obj = json.loads(policy)
        except Exception:
            return False

        entries = obj if isinstance(obj, list) else [obj]
        parsed_any = False

        for entry in entries:
            if not isinstance(entry, dict):
                continue

            sub = key_lookup(entry, {"subject", "sub", "user", "principal", "role", "actor"})
            res = key_lookup(entry, {"resource", "res", "object", "obj", "target"})
            act = key_lookup(entry, {"action", "act", "operation", "op", "permission"})
            eff = key_lookup(entry, {"effect", "eft", "decision", "type"})

