        if not acts:
            return

        matching_subjects = []
        for s in subjects:
            if s in subs or "*" in subs:
                matching_subjects.append(s)

        if not matching_subjects:
            return

        resource_matches = resource in ress or "*" in ress
        if not resource_matches:
            return

        clean_actions = []
        for a in acts:
            a = str(a).strip().strip("\"'")
            if a and a.lower() not in stop_words:
