from typing import List, Dict


def solve(subject: str, policies: list[str]) -> dict[str, bool]:
    levels = ["low", "medium", "high", "critical"]
    rank = {level: i for i, level in enumerate(levels)}

    subject_norm = str(subject).strip().lower()
    allowed = {level: False for level in levels}
    denied = {level: False for level in levels}

    level_synonyms = {
        "low": "low",
        "public": "low",
        "unclassified": "low",
        "medium": "medium",
        "moderate": "medium",
        "confidential": "medium",
        "restricted": "medium",
        "high": "high",
        "secret": "high",
        "critical": "critical",
        "topsecret": "critical",
        "top_secret": "critical",
        "top-secret": "critical",
        "ts": "critical",
    }

    allow_words = {
        "allow", "allows", "allowed", "grant", "grants", "granted",
        "permit", "permits", "permitted", "can", "may", "read",
        "access", "clearance", "clear", "cleared", "authorize",
        "authorized", "authorise", "authorised"
    }

    deny_words = {
