        "forbid", "forbids", "forbidden", "prohibit", "prohibits",
        "prohibited", "cannot", "can't", "cant", "maynot", "never",
        "revoke", "revokes", "revoked", "no"
    }

    wildcard_words = {"*", "all", "any", "everyone", "everybody", "users", "subjects"}

    def tokenize(text: str) -> list[str]:
        return re.findall(r"[a-z0-9_@.+*-]+", text.lower())

    def applies_to_subject(text: str, tokens: list[str]) -> bool:
        if any(tok in wildcard_words for tok in tokens):
            return True
        if not subject_norm:
            return False

