    effects_allow = {"allow", "allowed", "permit", "permits", "permitted", "grant", "grants", "granted", "yes", "true"}
    effects_deny = {"deny", "denied", "disallow", "disallowed", "forbid", "forbidden", "prohibit", "prohibited", "no", "false"}
