            r"\bcan\b", r"\bmay\b", r"\ballow(?:ed|s)?\b", r"\bpermit(?:ted|s)?\b",
            r"\bgrant(?:ed|s)?\b", r"\bauthorized\b", r"\bhas\b", r"\bhave\b"
        ]

        effect = None
        if any(re.search(p, low) for p in deny_patterns):
            effect = "deny"
        elif any(re.search(p, low) for p in allow_patterns):
            effect = "allow"
        else:
            effect = "allow"

        for r, start, end in res_positions:
