    deny_effects = {"deny", "denied", "disallow", "disallowed", "forbid", "forbidden", "false", False}

    def norm_tokens(s: Any) -> list[str]:
        s = str(s).strip().lower()
        s = re.sub(r"([=:,;|()\[\]{}\"'`<>])", " ", s)
        s = re.sub(r"\s+", " ", s)
        return [t for t in s.split(" ") if t]

    def contains_seq(tokens: list[str], seq: list[str]) -> bool:
        if not seq:
            return False
        n = len(seq)
        for i in range(len(tokens) - n + 1):
            if tokens[i:i + n] == seq:
                return True
        return False

    def mark_seq(tokens: list[str], seq: list[str], mask: list[bool], first_only: bool = False) -> bool:
        if not seq:
            return False
        found = False
        n = len(seq)
        for i in range(len(tokens) - n + 1):
            if tokens[i:i + n] == seq:
                for j in range(i, i + n):
                    mask[j] = True
                found = True
                if first_only:
                    return True
        return found

    def val_list(v: Any) -> list[str]:
        if v is None:
            return []
        if isinstance(v, (list, tuple, set)):
            out: list[str] = []
            for x in v:
                out.extend(val_list(x))
