        s = str(v).strip()
        if not s:
            return []
        parts = re.split(r"\s*,\s*|\s*;\s*|\s*\|\s*", s)
        return [p.strip() for p in parts if p.strip()]

    def match_value(value: str, target: str) -> bool:
        value_s = str(value).strip()
        target_s = str(target).strip()
        if value_s in {"*", "all", "any"}:
