        if not tokens:
            continue

        is_deny = any(t in deny_words for t in tokens) or ("not" in tokens and "allow" in tokens)

        subject_match = contains_seq(tokens, subject_seq)
        if not subject_match:
            if tokens[0] in {"*", "everyone", "anyone"}:
                subject_match = True
            elif "all" in tokens and ("users" in tokens or "subjects" in tokens or "principals" in tokens):
                subject_match = True
            elif "*" in tokens:
                for key in ("subject", "subjects", "user", "users", "principal", "principals"):
                    for i, t in enumerate(tokens[:-1]):
                        if t == key and tokens[i + 1] == "*":
                            subject_match = True
                            break
                    if subject_match:
                        break

        if not subject_match:
            continue

        matched_resources: list[str] = []
        for r, seq in resource_seqs.items():
            if contains_seq(tokens, seq):
                matched_resources.append(r)

        wildcard_resource = False
        if not matched_resources:
            if "*" in tokens:
                wildcard_resource = True
            elif "all" in tokens and ("resources" in tokens or "objects" in tokens):
                wildcard_resource = True
            elif "any" in tokens and ("resource" in tokens or "resources" in tokens or "object" in tokens):
                wildcard_resource = True

        target_resources = matched_resources if matched_resources else (list(resources) if wildcard_resource else [])
        if not target_resources:
            continue

        mask = [False] * len(tokens)
        mark_seq(tokens, subject_seq, mask, first_only=True)

        for seq in resource_seqs.values():
            mark_seq(tokens, seq, mask)

        for i, t in enumerate(tokens):
            if t in stop_words:
                mask[i] = True

        for i, t in enumerate(tokens):
            if t == "*" and wildcard_resource:
                left = [tokens[j] for j in range(len(tokens)) if not mask[j] and j != i]
                if left:
                    mask[i] = True
                    break

        actions = [tokens[i] for i in range(len(tokens)) if not mask[i]]

        if not actions:
            continue

        for r in target_resources:
            apply(r, actions, is_deny)

    return result

