def solve(subject: str, resources: list[str], policies: list[str]) -> dict[str, list[str]]:
    result = {r: [] for r in resources}
    denied = {r: set() for r in resources}

    effect_allow = {"allow", "allowed", "permit", "permits", "grant", "grants", "accept", "yes", "true"}
    effect_deny = {"deny", "denied", "forbid", "forbidden", "disallow", "disallowed", "reject", "no", "false"}

    def split_values(value):
        if value is None:
            return ["*"]
        if isinstance(value, (list, tuple, set)):
            out = []
            for v in value:
                out.extend(split_values(v))
            return out
        value = str(value).strip().strip('"').strip("'")
        if not value:
            return []
        parts = re.split(r"\s*(?:,|\||;)\s*", value)
        return [p for p in (x.strip() for x in parts) if p]

    def matches(pattern, value):
        if pattern is None:
            return True
        pattern = str(pattern).strip()
        if pattern in {"*", "all", "any", "ANY", "ALL"}:
            return True
        return pattern == value or fnmatch.fnmatchcase(value, pattern)

    def any_match(patterns, value):
        return any(matches(p, value) for p in patterns)

    def looks_like_resource(token):
        return any(matches(token, r) or matches(r, token) for r in resources)

    def parse_key_value_policy(text):
        cleaned = text.replace(",", " ")
        try:
            parts = shlex.split(cleaned)
        except Exception:
            parts = cleaned.split()

        data = {}
        for part in parts:
            if "=" in part:
                k, v = part.split("=", 1)
            elif ":" in part and not part.startswith(("http://", "https://")):
                k, v = part.split(":", 1)
            else:
                continue
            data[k.strip().lower()] = v.strip()

        if not data:
            return []

        aliases = {
            "subject": ("subject", "sub", "user", "principal", "role", "actor"),
            "resource": ("resource", "res", "object", "obj", "target"),
            "action": ("action", "act", "operation", "op", "permission", "perm"),
            "effect": ("effect", "eft", "decision", "access"),
        }

        def get(name):
            for key in aliases[name]:
                if key in data:
                    return data[key]
            return None

        sub = get("subject")
        res = get("resource")
        act = get("action")
        eff = get("effect") or "allow"

        if sub is None or res is None or act is None:
            return []

        eff_l = str(eff).strip().lower()
        if eff_l in effect_deny:
            effect = "deny"
        elif eff_l in effect_allow:
            effect = "allow"
        else:
            effect = "allow"

        return [(effect, split_values(sub), split_values(res), split_values(act))]

    def parse_json_policy(text):
        try:
            obj = json.loads(text)
        except Exception:
            return []

        if not isinstance(obj, dict):
            return []

        def get(*names):
            for n in names:
                if n in obj:
                    return obj[n]
            return None

        sub = get("subject", "sub", "user", "principal", "role", "actor")
        res = get("resource", "res", "object", "obj", "target")
        act = get("action", "act", "operation", "op", "permission", "perm")
        eff = get("effect", "eft", "decision", "access")
