        s = s.strip()
        while len(s) >= 2 and ((s[0] == s[-1] == '"') or (s[0] == s[-1] == "'")):
            s = s[1:-1].strip()
        if len(s) >= 2 and ((s[0], s[-1]) in {("(", ")"), ("[", "]"), ("{", "}")}):
            inner = s[1:-1].strip()
            if balanced(inner):
                return inner
        return s

    def balanced(s: str) -> bool:
        stack = []
        pairs = {")": "(", "]": "[", "}": "{"}
        quote = None
        esc = False
        for ch in s:
            if quote:
                if esc:
                    esc = False
                elif ch == "\\":
