import ast
from fractions import Fraction


_NUM_RE = re.compile(r'[-+]?(?:(?:\d+(?:\.\d*)?)|(?:\.\d+))(?:[eE][-+]?\d+)?')


def _to_fraction(s):
    s = s.strip()
    if re.fullmatch(r'[-+]?\d+\s*/\s*[-+]?\d+', s):
        a, b = s.split('/', 1)
        return Fraction(int(a.strip()), int(b.strip()))
    return Fraction(s)


def _safe_eval(expr, n):
    expr = expr.strip()
    if not expr:
        raise ValueError

    if '=' in expr:
        expr = expr.split('=')[-1].strip()

    expr = expr.replace('…', '...')
    expr = expr.replace('^', '**')
    expr = re.sub(r'\bpi\b', 'pi', expr, flags=re.I)

    expr = re.sub(r'(?<=\d)(?=[A-Za-z_(])', '*', expr)
    expr = re.sub(r'(?<=\))(?=(?:\d|[A-Za-z_]))', '*', expr)
    expr = re.sub(r'(?<=[A-Za-z_])(?=\()', '*', expr)

    allowed_names = {
        'n': n, 'i': n, 'x': n, 'k': n, 'index': n,
        'N': n + 1,
        'pi': math.pi, 'e': math.e,
        'abs': abs, 'round': round,
