            a = _to_fraction(m.group(1))
            b = _to_fraction(m.group(2))
            step = Fraction(1) if b >= a else Fraction(-1)
            return float(a + step * index)
    except Exception:
        pass

    terms = _parse_terms(s)
    if terms:
        return _from_terms(terms, index)

    try:
        return _safe_eval(s, index)
    except Exception:
        return float('nan')

