def _to_float(value: Any) -> float:
    if isinstance(value, bool):
        return float(int(value))
    if isinstance(value, (int, float)):
        return float(value)
    s = str(value).strip().strip("'\"")
    return float(s)


def _key_sort_value(key: Any):
    if isinstance(key, bool):
        return (0, float(int(key)))
    if isinstance(key, (int, float)):
        return (0, float(key))

    s = str(key).strip().strip("'\"")

    try:
        return (0, float(s))
    except ValueError:
        pass

    try:
        return (1, datetime.fromisoformat(s.replace("Z", "+00:00")).timestamp())
    except ValueError:
        pass

    return (2, s)


def _is_pair(obj: Any) -> bool:
    return isinstance(obj, (list, tuple)) and len(obj) == 2


def _parse_literal(series: str):
    try:
        return ast.literal_eval(series)
    except Exception:
