def _parse(series: str):
    series = (series or "").strip()
    if not series:
        return ("values", [])

    obj = _parse_literal(series)

    if isinstance(obj, dict):
        items = sorted(obj.items(), key=lambda kv: _key_sort_value(kv[0]))
        return ("keyed", [(k, _to_float(v)) for k, v in items])

    if isinstance(obj, (list, tuple)):
        if all(_is_pair(x) for x in obj):
            return ("keyed", [(x[0], _to_float(x[1])) for x in obj])
        return ("values", [_to_float(x) for x in obj])

    if isinstance(obj, (int, float)):
        return ("values", [float(obj)])

