    for line in re.split(r"[\n;]+", series):
        line = line.strip()
        if not line:
            continue

        if ":" in line:
            left, right = line.split(":", 1)
            nums = _NUM_RE.findall(right)
            if nums:
                pairs.append((left.strip().strip(", "), float(nums[0])))

    if pairs:
        return ("keyed", pairs)

