import re
from decimal import Decimal, InvalidOperation

def solve(series1: str, series2: str) -> int:
    def normalize(x):
        if x is None:
            return None
        s = str(x).strip()
        if not s:
            return None
        if (len(s) >= 2) and ((s[0] == s[-1] == '"') or (s[0] == s[-1] == "'")):
            s = s[1:-1].strip()
        s = s.strip(" \t\r\n,;|()[]{}")
        if not s:
            return None
        if s.lower() in {"timestamp", "time", "date", "datetime", "ts"}:
            return None

        if re.fullmatch(r"[+-]?\d+", s):
            try:
                return str(int(s))
            except Exception:
                return s

        if re.fullmatch(r"[+-]?(?:\d+\.\d*|\.\d+|\d+)(?:[eE][+-]?\d+)?", s):
            try:
                d = Decimal(s)
                if d == d.to_integral():
                    return str(int(d))
                return format(d.normalize(), "f").rstrip("0").rstrip(".")
            except (InvalidOperation, ValueError):
                return s

        return s

    def is_container(obj):
        return isinstance(obj, (list, tuple, set, dict))

    def add(out, value):
        v = normalize(value)
        if v is not None:
            out.add(v)

    def extract_structured(obj):
        out = set()
        keys = {"timestamp", "time", "date", "datetime", "ts"}

        def rec(o, top=False):
            if isinstance(o, dict):
                lowered = {str(k).lower(): k for k in o.keys()}
                for k in keys:
                    if k in lowered:
                        add(out, o[lowered[k]])
                        return
                for k in o.keys():
                    add(out, k)
                return

            if isinstance(o, (list, tuple, set)):
                seq = list(o)
                if not seq:
                    return

                if (
                    len(seq) >= 2
                    and not is_container(seq[0])
                    and not is_container(seq[1])
                    and (not top or len(seq) == 2)
                ):
                    add(out, seq[0])
                    return

                for item in seq:
                    if isinstance(item, dict):
                        rec(item)
                    elif isinstance(item, (list, tuple)):
                        if item:
                            add(out, item[0])
                    elif isinstance(item, set):
                        rec(item)
                    else:
                        add(out, item)
                return

            add(out, o)

        rec(obj, top=True)
        return out

    def parse_raw(s):
        out = set()
        text = s.strip()
        if not text:
            return out

        colon_pairs = re.findall(r"(?:^|[,\n;|])\s*([^:,\n;|]+?)\s*:", text)
        if colon_pairs and len(colon_pairs) > 1:
            for key in colon_pairs:
                add(out, key)
            if out:
                return out

        records = re.split(r"[\n;|]+", text)
        records = [r.strip() for r in records if r.strip()]

        if len(records) == 1 and ":" in records[0] and "," in records[0]:
            parts = re.split(r"\s*,\s*", records[0])
            if all(":" in p for p in parts):
                for p in parts:
                    add(out, p.split(":", 1)[0])
                if out:
                    return out

        for rec in records:
            rec = rec.strip()
            if not rec:
                continue

            if ":" in rec and "," not in rec and "\t" not in rec:
